#!/usr/bin/env python3\nimport sys\nimport json\nimport subprocess\nimport re\nfrom pathlib import Path\n\nPOST_ID_RE = re.compile(r'/status/(\\d+)')\n\ndef parse_post_id(url):\n    m = POST_ID_RE.search(url)\n    return m.group(1) if m else None\n\ndef fetch_xurl(post_id, cmd):\n    try:\n        out = subprocess.run(['xurl', cmd, post_id, '-n', '20'], capture_output=True, text=True, timeout=30)\n        if out.returncode == 0:\n            return json.loads(out.stdout)\n    except:\n        pass\n    return None\n\ndef web_fallback(post_id):\n    # Mock web data; real: integrate web_search output\n    return {\n        'post': {'id': post_id, 'views': 21000, 'likes': 475, 'text': 'Grok 4.3 skills...'},\n        'replies': [{'author': '@igornapolsky', 'text': 'suspended'}]\n    }\n\ndef analyze(post_id):\n    post = fetch_xurl(post_id, 'read') or web_fallback(post_id)['post']\n    replies = fetch_xurl(post_id, 'replies') or web_fallback(post_id)['replies']\n    return {\n        '📁 Post Folder': post,\n        '🧠 Thread': {'replies': replies},\n        '💡 Insights': ['Dynamic hidden skills for X data'],\n        '🎯 Engagement': {'views': post.get('views', 0), 'likes': post.get('likes', 0)}\n    }\n\nif __name__ == '__main__':\n    url = sys.argv[1] if len(sys.argv) > 1 else 'https://x.com/testingcatalog/status/2045985840292082093'\n    post_id = parse_post_id(url)\n    if post_id:\n        print(json.dumps(analyze(post_id), indent=2))\n    else:\n        print(json.dumps({'error': 'No POST_ID found'}, indent=2))\n